import React, { useState } from 'react';
import { useSpring, animated } from '@react-spring/web';
import { 
  X, 
  MessageCircle, 
  Search, 
  MoreHorizontal,
  Circle,
  Minus
} from 'lucide-react';

const MessagesPanel = ({ 
  isVisible, 
  onClose, 
  onConversationSelect, 
  selectedConversationId,
  conversations = []
}) => {
  const [isMinimized, setIsMinimized] = useState(false);
  const [activeTab, setActiveTab] = useState('priority');
  const [searchQuery, setSearchQuery] = useState('');

  // Animação do painel
  const panelAnimation = useSpring({
    transform: isVisible ? 'translateY(0%)' : 'translateY(100%)',
    opacity: isVisible ? 1 : 0,
    config: { tension: 300, friction: 30 }
  });

  // Animação da altura (minimizado/expandido)
  const heightAnimation = useSpring({
    height: isMinimized ? '60px' : '400px',
    config: { tension: 300, friction: 30 }
  });

  // Filtrar conversas baseado na aba ativa
  const filteredConversations = conversations.filter(conv => {
    const matchesSearch = conv.name.toLowerCase().includes(searchQuery.toLowerCase()) ||
                         conv.lastMessage.toLowerCase().includes(searchQuery.toLowerCase());

    if (activeTab === 'priority') {
      return matchesSearch && (conv.isPriority || conv.unreadCount > 0);
    }
    return matchesSearch;
  });

  const handleConversationClick = (conversation) => {
    onConversationSelect(conversation);
  };

  const toggleMinimize = () => {
    setIsMinimized(!isMinimized);
  };

  if (!isVisible) return null;

  return (
    <div className="fixed bottom-4 right-4 z-50">
      <animated.div
        style={{
          ...panelAnimation,
          ...heightAnimation,
          width: '320px'
        }}
        className="bg-neutral-800 border border-neutral-700 shadow-2xl rounded-lg overflow-hidden"
      >
        {/* Header */}
        <div className="bg-neutral-900 px-4 py-3 flex items-center justify-between border-b border-neutral-700">
          <div className="flex items-center space-x-2">
            <MessageCircle className="h-5 w-5 text-white" />
            <h3 className="text-white font-medium">Mensagens</h3>
            {conversations.filter(c => c.unreadCount > 0).length > 0 && (
              <div className="w-5 h-5 bg-red-500 rounded-full flex items-center justify-center">
                <span className="text-white text-xs font-bold">
                  {conversations.filter(c => c.unreadCount > 0).length}
                </span>
              </div>
            )}
          </div>
          <div className="flex items-center space-x-1">
            <button
              onClick={toggleMinimize}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <Minus className="h-4 w-4" />
            </button>
            <button
              onClick={onClose}
              className="p-1 text-gray-400 hover:text-white transition-colors"
            >
              <X className="h-4 w-4" />
            </button>
          </div>
        </div>

        {!isMinimized && (
          <>
            {/* Tabs */}
            <div className="flex border-b border-neutral-700">
              <button
                onClick={() => setActiveTab('priority')}
                className={`flex-1 px-4 py-2 text-sm font-medium transition-colors ${
                  activeTab === 'priority'
                    ? 'text-white border-b-2 border-white bg-neutral-700'
                    : 'text-neutral-400 hover:text-white'
                }`}
              >
                Prioritárias
              </button>
              <button
                onClick={() => setActiveTab('other')}
                className={`flex-1 px-4 py-2 text-sm font-medium transition-colors ${
                  activeTab === 'other'
                    ? 'text-white border-b-2 border-white bg-neutral-700'
                    : 'text-neutral-400 hover:text-white'
                }`}
              >
                Outras
              </button>
            </div>

            {/* Search */}
            <div className="p-3 border-b border-neutral-700">
              <div className="relative">
                <Search className="absolute left-3 top-1/2 transform -translate-y-1/2 h-4 w-4 text-neutral-400" />
                <input
                  type="text"
                  placeholder="Pesquisar mensagens..."
                  value={searchQuery}
                  onChange={(e) => setSearchQuery(e.target.value)}
                  className="w-full bg-neutral-700 border border-neutral-600 rounded-lg pl-10 pr-3 py-2 text-white text-sm focus:outline-none focus:ring-2 focus:ring-white focus:border-transparent"
                />
              </div>
            </div>

            {/* Conversations List */}
            <div className="flex-1 overflow-y-auto max-h-[280px]">
              {filteredConversations.length === 0 ? (
                <div className="p-4 text-center text-neutral-400">
                  <MessageCircle className="h-8 w-8 mx-auto mb-2 opacity-50" />
                  <p className="text-sm">Nenhuma conversa encontrada</p>
                </div>
              ) : (
                filteredConversations.map((conversation) => (
                  <div
                    key={conversation.id}
                    onClick={() => handleConversationClick(conversation)}
                    className={`p-3 border-b border-neutral-700 cursor-pointer transition-colors hover:bg-neutral-700 ${
                      selectedConversationId === conversation.id ? 'bg-neutral-700' : ''
                    }`}
                  >
                    <div className="flex items-start space-x-3">
                      <div className="relative">
                        <img
                          src={conversation.avatar}
                          alt={conversation.name}
                          className="w-10 h-10 rounded-full"
                        />
                        <div className={`absolute -bottom-0.5 -right-0.5 w-3 h-3 rounded-full border-2 border-neutral-800 ${
                          conversation.status === 'online' ? 'bg-green-500' : 
                          conversation.status === 'away' ? 'bg-orange-500' : 'bg-gray-500'
                        }`} />
                        {conversation.unreadCount > 0 && (
                          <div className="absolute -top-1 -right-1 w-5 h-5 bg-red-500 rounded-full flex items-center justify-center">
                            <span className="text-white text-xs font-bold">
                              {conversation.unreadCount > 9 ? '9+' : conversation.unreadCount}
                            </span>
                          </div>
                        )}
                      </div>
                      <div className="flex-1 min-w-0">
                        <div className="flex items-center justify-between">
                          <h4 className={`font-medium truncate ${
                            conversation.unreadCount > 0 ? 'text-white' : 'text-neutral-300'
                          }`}>
                            {conversation.name}
                          </h4>
                          <span className="text-xs text-neutral-400 ml-2">
                            {conversation.timestamp}
                          </span>
                        </div>
                        <p className={`text-sm truncate mt-1 ${
                          conversation.unreadCount > 0 ? 'text-neutral-300' : 'text-neutral-400'
                        }`}>
                          {conversation.lastMessage}
                        </p>
                        {conversation.isPriority && (
                          <div className="flex items-center mt-1">
                            <Circle className="h-2 w-2 text-red-500 fill-current mr-1" />
                            <span className="text-xs text-red-400">Prioritária</span>
                          </div>
                        )}
                      </div>
                    </div>
                  </div>
                ))
              )}
            </div>
          </>
        )}
      </animated.div>
    </div>
  );
};

export default MessagesPanel;
